INSERT OR IGNORE INTO articles (id, url, title, source, track, license, attribution, published_at, fetched_at) VALUES ('vocab-set-1', '', 'GRE vocabulary, set 1', 'authored', 'vocab', 'cc0', 'GRE-level vocabulary with plain-English definitions — original content (CC0)', NULL, datetime('now'));
INSERT OR IGNORE INTO passages (article_id, seq, text, word_count) VALUES ('vocab-set-1', 0, 'Abate: to become less strong or intense. Aberrant: departing from what is normal or expected. Abstruse: hard to understand without special knowledge. Alacrity: cheerful and eager readiness. Ambivalent: holding mixed feelings about something.', 33);
INSERT OR IGNORE INTO passages (article_id, seq, text, word_count) VALUES ('vocab-set-1', 1, 'Ameliorate: to make a bad situation better. Anomaly: something that differs from the usual pattern. Antipathy: a deep and lasting dislike. Arduous: requiring great effort and endurance. Assuage: to soothe a feeling or ease a pain.', 36);
INSERT OR IGNORE INTO passages (article_id, seq, text, word_count) VALUES ('vocab-set-1', 2, 'Audacious: boldly daring, often beyond convention. Austere: severe, plain, and without comfort. Belie: to give a false impression of something. Bolster: to support, strengthen, or reinforce. Burgeon: to grow or expand rapidly.', 32);
INSERT OR IGNORE INTO passages (article_id, seq, text, word_count) VALUES ('vocab-set-1', 3, 'Cacophony: a harsh mixture of unpleasant sounds. Capricious: changing mood or behavior without warning. Castigate: to criticize or punish severely. Catalyst: something that triggers or speeds up change. Caustic: bitingly sarcastic or corrosive.', 33);
INSERT OR IGNORE INTO passages (article_id, seq, text, word_count) VALUES ('vocab-set-1', 4, 'Chicanery: trickery used to deceive someone. Cogent: clear, logical, and convincing. Commensurate: matching something in size or degree. Conciliatory: intended to calm anger and restore trust. Confound: to confuse, or to prove wrong in a surprising way.', 37);

INSERT OR IGNORE INTO articles (id, url, title, source, track, license, attribution, published_at, fetched_at) VALUES ('vocab-set-2', '', 'GRE vocabulary, set 2', 'authored', 'vocab', 'cc0', 'GRE-level vocabulary with plain-English definitions — original content (CC0)', NULL, datetime('now'));
INSERT OR IGNORE INTO passages (article_id, seq, text, word_count) VALUES ('vocab-set-2', 0, 'Convoluted: twisted and overly complicated. Copious: present in large and plentiful amounts. Corroborate: to confirm with supporting evidence. Craven: shamefully lacking in courage. Cursory: quick and without careful attention.', 29);
INSERT OR IGNORE INTO passages (article_id, seq, text, word_count) VALUES ('vocab-set-2', 1, 'Dearth: a scarce supply or lack of something. Deference: polite respect for another''s judgment. Deleterious: causing harm, often subtly. Demur: to raise a polite objection. Denigrate: to unfairly belittle or defame.', 31);
INSERT OR IGNORE INTO passages (article_id, seq, text, word_count) VALUES ('vocab-set-2', 2, 'Desultory: aimless and lacking a plan. Diatribe: a bitter verbal attack. Didactic: intended to teach, often preachily. Diffident: shy from lack of self-confidence. Dilatory: slow, tending to cause delay.', 29);
INSERT OR IGNORE INTO passages (article_id, seq, text, word_count) VALUES ('vocab-set-2', 3, 'Disparate: so different as to defy comparison. Dogmatic: asserting opinions as unquestionable truth. Ebullient: overflowing with cheerful energy. Eclectic: drawn from many different sources. Efficacy: the power to produce the intended result.', 32);
INSERT OR IGNORE INTO passages (article_id, seq, text, word_count) VALUES ('vocab-set-2', 4, 'Elucidate: to explain and make clear. Empirical: based on observation rather than theory. Enervate: to drain of strength or vitality. Engender: to cause a feeling or condition to arise. Ephemeral: lasting for only a very short time.', 37);

INSERT OR IGNORE INTO articles (id, url, title, source, track, license, attribution, published_at, fetched_at) VALUES ('vocab-set-3', '', 'GRE vocabulary, set 3', 'authored', 'vocab', 'cc0', 'GRE-level vocabulary with plain-English definitions — original content (CC0)', NULL, datetime('now'));
INSERT OR IGNORE INTO passages (article_id, seq, text, word_count) VALUES ('vocab-set-3', 0, 'Equivocate: to speak vaguely to avoid commitment. Erudite: showing deep scholarly knowledge. Esoteric: understood by only a small circle. Eulogy: a speech of high praise, often for the dead. Exacerbate: to make a problem worse.', 35);
INSERT OR IGNORE INTO passages (article_id, seq, text, word_count) VALUES ('vocab-set-3', 1, 'Exculpate: to clear someone of blame. Exigent: urgent and demanding immediate action. Facetious: joking at an inappropriate moment. Fastidious: extremely attentive to detail and standards. Fervent: intensely passionate and heartfelt.', 30);
INSERT OR IGNORE INTO passages (article_id, seq, text, word_count) VALUES ('vocab-set-3', 2, 'Fortuitous: happening by lucky chance. Frugal: careful and sparing with money or resources. Garrulous: talking too much about trivial things. Gregarious: sociable and fond of company. Hackneyed: worn out from overuse; unoriginal.', 32);
INSERT OR IGNORE INTO passages (article_id, seq, text, word_count) VALUES ('vocab-set-3', 3, 'Harangue: a long, aggressive lecture. Iconoclast: one who attacks cherished beliefs. Impetuous: acting suddenly without thought. Inchoate: just begun and not yet fully formed. Indefatigable: never tiring, persistently energetic.', 29);
INSERT OR IGNORE INTO passages (article_id, seq, text, word_count) VALUES ('vocab-set-3', 4, 'Ineffable: too great to be expressed in words. Ingenuous: innocently frank and trusting. Insipid: dull, flat, and lacking flavor or interest. Intransigent: refusing to compromise. Inveterate: long established and unlikely to change.', 32);

INSERT OR IGNORE INTO articles (id, url, title, source, track, license, attribution, published_at, fetched_at) VALUES ('vocab-set-4', '', 'GRE vocabulary, set 4', 'authored', 'vocab', 'cc0', 'GRE-level vocabulary with plain-English definitions — original content (CC0)', NULL, datetime('now'));
INSERT OR IGNORE INTO passages (article_id, seq, text, word_count) VALUES ('vocab-set-4', 0, 'Irascible: easily provoked to anger. Laconic: using very few words. Laud: to praise highly. Loquacious: extremely talkative. Magnanimous: generous toward a rival or enemy.', 24);
INSERT OR IGNORE INTO passages (article_id, seq, text, word_count) VALUES ('vocab-set-4', 1, 'Mendacious: habitually dishonest. Mercurial: unpredictably changeable in mood. Mitigate: to reduce the severity of something. Mollify: to calm someone''s anger. Myopic: short-sighted in judgment or planning.', 26);
INSERT OR IGNORE INTO passages (article_id, seq, text, word_count) VALUES ('vocab-set-4', 2, 'Nascent: newly born and beginning to develop. Obdurate: stubbornly refusing to change one''s mind. Obfuscate: to deliberately make unclear. Obsequious: excessively eager to please or obey. Obviate: to make unnecessary by anticipation.', 32);
INSERT OR IGNORE INTO passages (article_id, seq, text, word_count) VALUES ('vocab-set-4', 3, 'Onerous: involving a heavy, oppressive burden. Ostentatious: showy in a way meant to impress. Paucity: a shortage; too small an amount. Pedantic: overly concerned with minor rules and detail. Perfunctory: done as a routine, without care.', 36);
INSERT OR IGNORE INTO passages (article_id, seq, text, word_count) VALUES ('vocab-set-4', 4, 'Pragmatic: guided by practical results, not theory. Prescient: knowing events before they happen. Prevaricate: to avoid telling the truth directly. Prodigal: wastefully extravagant. Quiescent: quiet, still, and inactive for a time.', 31);

INSERT OR IGNORE INTO articles (id, url, title, source, track, license, attribution, published_at, fetched_at) VALUES ('vocab-set-5', '', 'GRE vocabulary, set 5', 'authored', 'vocab', 'cc0', 'GRE-level vocabulary with plain-English definitions — original content (CC0)', NULL, datetime('now'));
INSERT OR IGNORE INTO passages (article_id, seq, text, word_count) VALUES ('vocab-set-5', 0, 'Recalcitrant: stubbornly resistant to authority. Taciturn: habitually silent and reserved.', 10);
